Here's a complete example:

**XAML**
```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             x:Class="MyApp.Views.ItemsPage">

    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem}"
                    IsRefreshing="{Binding IsRefreshing}"
                    RemainingItemsThreshold="0">

        <!-- Pull-to-refresh via RefreshView wrapper -->
        <CollectionView.Behaviors>
            <!-- or wrap in RefreshView instead -->
        </CollectionView.Behaviors>

    </CollectionView>
</ContentPage>
```

In practice, wrap the `CollectionView` in a `RefreshView` since `CollectionView` itself doesn't own refresh:

```xml
<RefreshView Command="{Binding RefreshCommand}"
             IsRefreshing="{Binding IsRefreshing}">

    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem, Mode=TwoWay}">
        <CollectionView.ItemTemplate>
            <DataTemplate>
                <Grid Padding="12" ColumnDefinitions="*,Auto">
                    <Label Text="{Binding Name}" FontSize="16" />
                    <Label Grid.Column="1" Text="{Binding Status}"
                           TextColor="Gray" />
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
    </CollectionView>

</RefreshView>
```

**ViewModel** (using CommunityToolkit.Mvvm):
```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private ObservableCollection<Item> _items = new();

    [ObservableProperty]
    private bool _isRefreshing;

    private Item? _selectedItem;
    public Item? SelectedItem
    {
        get => _selectedItem;
        set
        {
            if (SetProperty(ref _selectedItem, value) && value is not null)
            {
                // Navigate, then clear selection so the user
                // can re-select the same item later.
                _nav.GoToAsync("DetailPage", new() { ["Item"] = value });
                SelectedItem = null;
            }
        }
    }

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            Items = new ObservableCollection<Item>(data);
        }
        finally
        {
            IsRefreshing = false;   // stops the spinner
        }
    }
}
```

**Key binding points:**

| XAML Property | ViewModel Property | Purpose |
|---|---|---|
| `ItemsSource` | `Items` (ObservableCollection) | Drives the list |
| `SelectedItem` (TwoWay) | `SelectedItem` | Fires navigation on selection |
| `RefreshView.Command` | `RefreshCommand` | Triggers API reload on pull |
| `RefreshView.IsRefreshing` | `IsRefreshing` | Controls the refresh spinner |

**Why `SelectedItem = null`?** — Without clearing it, selecting the same row twice won't fire the setter again because the value hasn't changed.

**Why `IsRefreshing = false` in `finally`?** — Guarantees the spinner stops even if the API call throws.
